#include <algorithm>
#include <string>

using namespace std;

string solve(string s) {
    string result;
    for (char c : s) {
        if (c >= 'a' && c <= 'z') {
            result += c;
        } else if (c == '*') {
            if (!result.empty()) {
                result.pop_back();
            }
        } else if (c == '#') {
